mapper.select:
select minerOrder.uuid id,minerOrder.order_no order_no ,minerOrder.miner_id minerId , minerOrder.amount amount,DATE_FORMAT(minerOrder.create_time,'%Y-%m-%d %H:%i:%S') create_time, DATE(minerOrder.earn_time) earn_time,DATE(minerOrder.stop_time) stop_time,minerOrder.profit profit, minerOrder.state state,minerOrder.base_compute_amount base_compute_amount, miner.cycle cycle,miner.cycle_close cycle_close,miner.daily_rate daily_rate,miner.test test, miner.name miner_name,miner.name_en miner_name_en,miner.name_cn miner_name_cn FROM t_miner_order minerOrder LEFT JOIN t_miner miner ON miner.uuid= minerOrder.miner_id where 1=1
AND minerOrder.party_id=#{partyId}
AND minerOrder.state in('0','2')
AND minerOrder.state=#{state}
order by minerOrder.create_time desc

SELECT minerOrder.uuid id,minerOrder.order_no order_no ,minerOrder.miner_id minerId , minerOrder.amount amount,minerOrder.create_time create_time,minerOrder.base_compute_amount base_compute_amount, minerOrder.earn_time earn_time,minerOrder.stop_time stop_time,minerOrder.profit profit, minerOrder.state state,minerOrder.close_time close_time,minerOrder.default_money default_money, party.user_name username,party.user_code usercode,party.role_name rolename, miner.name miner_name,miner.name_en miner_name_en FROM t_miner_order minerOrder LEFT JOIN tz_user party ON minerOrder.party_id = party.user_id LEFT JOIN t_miner miner ON miner.uuid = minerOrder.miner_id WHERE 1 = 1
and minerOrder.party_id in
#{item}
and miner.name=#{miner_para}
AND (party.user_name like CONCAT('%', #{name_para}, '%') OR party.user_code like CONCAT('%', #{name_para}, '%'))
and minerOrder.STATE = #{status_para}
and (minerOrder.STATE ='0' OR minerOrder.STATE ='2' )
and minerOrder.order_no =#{orderNo}
and party.role_name =#{rolename_para}
order by minerOrder.close_time desc
order by minerOrder.create_time desc
order by minerOrder.create_time desc
